  import sailpoint.tools.Util;
  import sailpoint.object.Custom;
  import sailpoint.tools.Message;

  import sailpoint.object.Filter;
  import sailpoint.object.Identity;
  import sailpoint.object.QueryOptions;

  import sailpoint.api.IdentityService;
  import sailpoint.object.Link;
  import sailpoint.object.Application;
  import sailpoint.object.TaskDefinition;

  import sailpoint.object.EmailOptions;
  import sailpoint.object.EmailTemplate;
  import sailpoint.object.EmailFileAttachment;

  import org.apache.commons.logging.LogFactory;
  import org.apache.commons.logging.Log;

  Log logger = LogFactory.getLog("Ascension-Rule-BulkUsers-Report");

  /**
	 * @param data
	 * @param templateName
	 * @param emailID
	 * @param notes
	 */
  public void sendEmailNow(String data, String templateName, String emailID, String notes){
    logger.debug("Entering method sendEmailNow");
    if(Util.isNotNullOrEmpty(data) && Util.isNotNullOrEmpty(templateName) && Util.isNotNullOrEmpty(emailID) && Util.isNotNullOrEmpty(notes)){
      EmailTemplate emailTemplate = context.getObject(EmailTemplate.class,templateName);
      EmailOptions emailOptions = new EmailOptions();
      emailOptions.setSendImmediate(true);
      emailOptions.setNoRetry(true);
      emailOptions.setTo(emailID);

      byte[] dataTobeSent=readBytesFromFile(data);
      String outputFileName = "Bulk Users Upload Data.csv";
      EmailFileAttachment attachment = new EmailFileAttachment(outputFileName , EmailFileAttachment.MimeType.MIME_CSV, dataTobeSent );
      emailOptions.addAttachment( attachment );

      Map emailArgs=new HashMap();
      emailArgs.put("outputFileName",outputFileName);
      emailArgs.put("notes",notes);

      emailOptions.setVariables(emailArgs);
      context.sendEmailNotification(emailTemplate,emailOptions);
    }
    logger.debug("Exiting method sendEmailNow");
  }

  /**
	 * @param resultCSVString
	 * @return
	 * @throws IOException
	 */
  public byte[] readBytesFromFile(String resultCSVString) throws IOException {
    logger.debug("Entering readBytesFromFile Method");
    InputStream fileInputStream = null;    
    byte[] bytesArray = null;
    try {
      bytesArray = resultCSVString.getBytes();
    } finally {
      if (fileInputStream != null) {
        try {
          fileInputStream.close();
        } catch (IOException e) {
          logger.error("Exception occured while closing the file input stream of output file: "+e.getMessage());
        }
      }
    }
    logger.debug("Exiting readBytesFromFile Method");
    return bytesArray;
  }


  /**
	 * @param notesUsers
	 * @param headerString
	 * @return
	 */
  public String convertData(List notesUsers,String headerString){
    logger.debug("Entering method convertData");
    StringBuffer data = new StringBuffer();
    int headerLength = 0;
    String[] headerSplit = null;
    if (Util.isNotNullOrEmpty(headerString) && headerString.contains("|")) {
      data.append(headerString);
      data.append("\n");
      headerSplit = headerString.split("\\|");
      if (headerSplit != null) {
        headerLength = headerSplit.length;
      }
    }
    if(!Util.isEmpty(notesUsers)){
      for(Map eachMap : notesUsers){
        if(!Util.isEmpty(eachMap) && headerSplit != null){
          for(int count=0; count < headerLength; count++){
            String value= eachMap.get(headerSplit[count]);
            data.append(Util.isNotNullOrEmpty(value) ? value : " ");
            if(count != eachMap.size()-1)
              data.append("|");
          }
          data.append("\n");
        }
      }
    }
    logger.debug("Exiting method convertData");
    return data.toString();
  }


  /**
	 * @param notes
	 * @return
	 */
  public List getIdentitiesFromNotes(String notes){
    logger.debug("Entering method getIdentitiesFromNotes");
    List notesUsers = new ArrayList();
    if(Util.isNotNullOrEmpty(notes)){
      Filter noteFilter = Filter.eq("notes", notes);
      QueryOptions qo = new QueryOptions();
      qo.add(noteFilter);

      Iterator iter = context.search(Identity.class, qo);
      while(iter != null && iter.hasNext()) {
        String networkID = null;
        String mail = null;
        Date identityCreated = null;
        Date linkCreated = null;
        Map attributesMap = new HashMap();
        Identity currentUser = iter.next();

        if(currentUser != null) {
          IdentityService identityService = new IdentityService(context);
          QueryOptions qo2  = new QueryOptions();
          qo2.addFilter(Filter.eq("type", "Active Directory - Direct"));
          qo2.addOrdering("created", true);
          List adApps = context.getObjects(Application.class, qo2);
          List links = Util.filterNulls(identityService.getLinks(currentUser, adApps, null));
          if(!Util.isEmpty(links)){
            for (Object object : links) {
              Link link = (Link) object;
              if(link!=null){
                networkID = (String) link.getAttribute("msDS-PrincipalName");
                mail = (String) link.getAttribute("mail");
                identityCreated = currentUser.getCreated();
                linkCreated = link.getCreated();
                break;
              }
            }
          }
          String dob = currentUser.getAttribute("dob");
          String monthVal = null;
          String dateVal = null;
          String[] dobSplit = null;
          if(Util.isNotNullOrEmpty(dob) && dob.contains("/") && dob.length() <=5){
            dobSplit = dob.split("/");
          }
          else{
            String decryptedDate = decryptAES(dob);
            if(Util.isNotNullOrEmpty(decryptedDate) && decryptedDate.contains("/")){
              dobSplit = decryptedDate.split("/");
            }
          }
          if (dobSplit != null && dobSplit.length ==2) {
            monthVal = dobSplit[0];
            dateVal = dobSplit[1];
          }
          boolean inactive = currentUser.getAttribute("inactive");
          if(inactive){
            attributesMap.put("disabled", "true");
          }else{
            attributesMap.put("disabled", "false");
          }
          attributesMap.put("student_id", Util.isNotNullOrEmpty(currentUser.getAttribute("internalid")) ? currentUser.getAttribute("internalid") : " ");
          attributesMap.put("authsource", "bulk");
          attributesMap.put("Name", Util.isNotNullOrEmpty(currentUser.getName()) ? currentUser.getName() : " ");
          attributesMap.put("First Name", Util.isNotNullOrEmpty(currentUser.getFirstname()) ? currentUser.getFirstname() : " ");
          attributesMap.put("Last Name", Util.isNotNullOrEmpty(currentUser.getLastname()) ? currentUser.getLastname() : " ");
          attributesMap.put("Middle Name", Util.isNotNullOrEmpty(currentUser.getAttribute("middleName")) ? currentUser.getAttribute("middleName") : " ");
          attributesMap.put("Mail", Util.isNotNullOrEmpty(mail) ? mail : " ");
          attributesMap.put("windows_acct", Util.isNotNullOrEmpty(networkID) ? networkID : " ");
          attributesMap.put("adlink_created", linkCreated != null ? Util.dateToString(linkCreated) : " ");
          attributesMap.put("identity_created", identityCreated != null ? Util.dateToString(identityCreated) : " ");
          attributesMap.put("Initial AD Password", " ");
          notesUsers.add(attributesMap);
          //comment decache //context.decache(currentUser);
        }
      }
      if(null != iter) {
        Util.flushIterator(iter);
      }
    }
    logger.debug("Exiting method getIdentitiesFromNotes");
    return notesUsers;
  }


  /**
	 * @param taskName
	 */
  public void changeNotesOnTaskDef(String taskName){
    logger.debug("Entering method changeNotesOnTaskDef");
    if(Util.isNotNullOrEmpty(taskName)){
      TaskDefinition taskDefObject = context.getObjectByName(TaskDefinition.class, taskName);
      if(taskDefObject != null){
        String taskNotes = taskDefObject.getArgument("notes");
        if(Util.isNotNullOrEmpty(taskNotes)){
          taskDefObject.setArgument("notes","");
          context.saveObject(taskDefObject);
          context.commitTransaction();
          //comment decache //context.decache(taskDefObject);
        }
      }
    }
    logger.debug("Exiting method changeNotesOnTaskDef");
  }


  if((void != config) && (null != config) && (config instanceof Map)){
    List notesUsers = new ArrayList();
    String templateName = null;
    String notesFromCustom = null;
    String email = null;
    String notes = config.get("notes");
    String headerString = null;
    String taskName = null;
    Map customValMap = new HashMap();
    Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
    if(custom != null && custom.get("BulkAmitaUserDetails") != null){
      customValMap = custom.get("BulkAmitaUserDetails");
      if(!Util.isEmpty(customValMap)){
        templateName = customValMap.get("BulkUsersEmailTemplate");
        // notesFromCustom = customValMap.get("Notes");
        headerString = customValMap.get("Header String");
        taskName = customValMap.get("Bulk Users Report Task Name");
      }
    }
    if(custom != null){
      //comment decache //context.decache(custom);
    }

    if(taskResult != void && taskResult != null){

      if(Util.isNotNullOrEmpty(notes)){
        notesUsers = getIdentitiesFromNotes(notes);
        changeNotesOnTaskDef(taskName);
        taskResult.setAttribute("notes",notes);
      }else{
        if(Util.isNotNullOrEmpty(notesFromCustom)){
          notesUsers=  getIdentitiesFromNotes(notesFromCustom);
          taskResult.setAttribute("notes",notesFromCustom);
        }
      }


      String launcherName = taskResult.getLauncher();
      if(Util.isNotNullOrEmpty(launcherName)){
        Identity launcherObj = context.getObjectByName(Identity.class,launcherName);
        if(launcherObj !=null){
          email = launcherObj.getAttribute("email");
          //comment decache //context.decache(launcherObj);
        }
      }


      if(!Util.isEmpty(notesUsers) && Util.isNotNullOrEmpty(templateName) && Util.isNotNullOrEmpty(headerString)){
        String data = convertData(notesUsers, headerString);

        if(Util.isNotNullOrEmpty(data) && Util.isNotNullOrEmpty(notes) &&  Util.isNotNullOrEmpty(email)){
          sendEmailNow(data, templateName, email, notes);

        }else{
          sendEmailNow(data, templateName, email, notesFromCustom);
        }
      }

      if(Util.isNotNullOrEmpty(email)){
        taskResult.setAttribute("email",email);  
      }else{
        taskResult.setAttribute("email","Email not found"); 
        taskResult.addMessage(new Message(Message.Type.Warn, "Launcher email not found", null));
      }
      taskResult.setAttribute("identityIncluded",Util.isEmpty(notesUsers)?"0":notesUsers.size());  

    }

  }
